gen-control.c:script:
return {
    type: 'tpl',
    tpl: '<span class="label label-${totalDebit == totalCredit ? "success" : "danger"}">' +
        '${totalDebit == totalCredit ? "✓ 平衡" : "✗ 不平衡"}</span>'
};

const valueProp = dispMeta?.id || 'docStatus';
const labelProp = propMeta?.['graphql:labelProp'] || (valueProp + '_label');
return {
    type: "tpl",
    tpl: '<span class="label label-${' + valueProp
        + " == 'ACTIVE' ? 'primary' : 'default'}\" "
        + "${" + valueProp
        + " == 'CANCELLED' ? \"style='text-decoration:line-through'\" : ''}>"
        + "${" + labelProp + "}</span>"
};

return {
    type: 'button',
    label: '刷新合计 + 借贷自动平衡（差额填入末行）',
    level: 'warning',
    icon: 'fa fa-balance-scale',
    onEvent: {
        click: {
            actions: [
                {
                    actionType: 'custom',
                    script: 'const lines = Array.isArray(event.data.lines) ? event.data.lines.slice() : []; const totalD = lines.reduce((s, l) => s + (Number(l.debitAmount) || 0), 0); const totalC = lines.reduce((s, l) => s + (Number(l.creditAmount) || 0), 0); if (lines.length === 0) { doAction({actionType:"setValue", args:{value:{totalDebit: 0, totalCredit: 0}}}); doAction({actionType:"toast", args:{msgtype:"info", msg:"无分录行"}}); return; } if (Math.abs(totalD - totalC) < 0.0001) { doAction({actionType:"setValue", args:{value:{totalDebit: totalD, totalCredit: totalC}}}); doAction({actionType:"toast", args:{msgtype:"success", msg:"凭证已平衡，合计已刷新"}}); return; } const last = lines[lines.length - 1]; const diff = totalD - totalC; if (diff > 0) { last.creditAmount = (Number(last.creditAmount) || 0) + diff; } else { last.debitAmount = (Number(last.debitAmount) || 0) + (-diff); } doAction({actionType:"setValue", args:{value:{lines: lines, totalDebit: totalD + (diff < 0 ? (-diff) : 0), totalCredit: totalC + (diff > 0 ? diff : 0)}}});'
                }
            ]
        }
    }
};
